const jobs = $input.first().json;

// Find the latest trend-radar job
let trendData = null;
if (Array.isArray(jobs)) {
  const trendJobs = jobs.filter(j => j.type === 'trend-radar' && j.status === 'complete');
  if (trendJobs.length > 0) {
    trendJobs.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
    trendData = trendJobs[0];
  }
} else if (jobs && jobs.type === 'trend-radar') {
  trendData = jobs;
}

let trendSummary = 'No recent trend data available.';
if (trendData && trendData.data && trendData.data.cards) {
  trendSummary = trendData.data.cards.slice(0, 10).map((c, i) => 
    `${i+1}. [${c.category}] ${c.title} - ${c.summary} (relevance: ${c.relevance}/10)`
  ).join('\n');
}

const prompt = `You are a content strategist for nVision Digital AI, an AI-focused digital agency. Based on the latest tech trends below, generate exactly 3 content ideas.

For each idea provide:
1. **title**: Catchy headline for a blog post or social media content
2. **format**: One of: blog_post, linkedin_post, twitter_thread, video_script, case_study
3. **hook**: Opening sentence that grabs attention (max 20 words)
4. **outline**: 3-5 bullet points of key topics to cover
5. **target_audience**: Who this content is for
6. **estimated_impact**: low/medium/high with reasoning
7. **trending_connection**: Which trend inspired this idea

Latest Trends:
${trendSummary}

Brand context: nVision Digital AI helps businesses leverage AI agents, automation, and modern web technology. The owner Nadav is an expert in AI integration, digital marketing, and web development.

Return ONLY a valid JSON array of 3 objects. No markdown, no explanation.`;

return [{ json: { prompt, trendSummary } }];

const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '[]';

let ideas;
try {
  const jsonMatch = content.match(/\[[\s\S]*\]/);
  ideas = JSON.parse(jsonMatch ? jsonMatch[0] : content);
} catch(e) {
  ideas = [{ title: 'Parse error', error: e.message, raw: content.substring(0, 500) }];
}

const jobPayload = {
  jobId: `content-ideas-${Date.now()}`,
  type: 'content-ideas',
  status: 'complete',
  timestamp: new Date().toISOString(),
  data: {
    ideas: ideas.map((idea, i) => ({
      id: `idea-${Date.now()}-${i}`,
      ...idea
    })),
    basedOnTrends: $('Build Content Prompt').first().json.trendSummary.substring(0, 200)
  }
};

return [{ json: jobPayload }];
